export function hasReportContent(slug: string): boolean {
  return slug in REPORT_CONTENT_LOADERS;
}

export async function loadReportContent(
  slug: string,
): Promise<ReportContent | undefined> {
  const loader = REPORT_CONTENT_LOADERS[slug];
  if (!loader) return undefined;
  return (await loader()).default;
}
